#!/usr/bin/perl

use strict;
use warnings;

use CGI;

my $q = CGI->new;

my $redirect_url = $q->param('next') || '/'; # Default to root if 'next' is not provided

# A CGI script must at minimum provide a Content-Type header.
# The web server will typically infer a 302 Found status if a Location header
# is present without an explicit Status header.
print "Content-type: text/html\n";
print "Location: $redirect_url\n\n";

# An optional small body for browsers that might not follow the redirect immediately
